Here's how to handle each scenario with modern MSTest attributes (3.9+/3.10+):

```csharp
[TestClass]
public sealed class EnvironmentSpecificTests
{
    private readonly TestContext _testContext;
    private string? _tempFilePath;

    public EnvironmentSpecificTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only (skipped on Linux/macOS)
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\MyApp", "Setting", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_ProducesExpectedOutput()
    {
        var result = GpuRenderer.RenderTestFrame();
        Assert.IsNotNull(result);
    }

    // 3. Flaky external API -- retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var forecast = await WeatherClient.GetForecastAsync(_testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Temp files cleaned up even on failure
    [TestMethod]
    public void Export_CreatesValidFile()
    {
        _tempFilePath = Path.GetTempFileName();
        Exporter.WriteTo(_tempFilePath);
        Assert.IsTrue(File.Exists(_tempFilePath));
    }

    // Runs after EVERY test, even on failure
    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFilePath is not null && File.Exists(_tempFilePath))
        {
            File.Delete(_tempFilePath);
        }
    }
}
```

**Summary of attributes:**

| Scenario | Attribute | Min Version |
|----------|-----------|-------------|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | 3.10 |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10 |
| Flaky retries | `[Retry(3)]` | 3.9 |
| Guaranteed cleanup | `[TestCleanup]` method | All |

Key notes:
- `[TestCleanup]` always runs after each test (pass or fail), making it ideal for temp file deletion.
- `[Retry]` should only be used for genuinely flaky external dependencies — not to mask race conditions.
- Pair `[Timeout]` with `TestContext.CancellationToken` on async tests to ensure proper cooperative cancellation.
